   multi_normal(const mu, const var_root)
   {		 
      decl ran;
      ran = rann(4, 1);  
	  ran = var_root*ran;  
	  ran = ran+mu;	 return ran;
	}  


	main()
	{
	   decl N=1000000;
	   decl sum = zeros(4, 4);
	   decl i, ran;

	   print(time());
	   decl mu = zeros(4,1);
	   decl var_root = unit(4);	  

	   for(i=0; i<N; i++)
	   {		  
	      ran = multi_normal(mu, var_root);
		  sum = sum + ran*ran';	  

		  }


		  sum = sum/N;
		  print(sum);
		  print(time());
}


