		  rm(list=ls(all=TRUE));
  rmulti.norm <- function(mean, var.root)
  {    
     ran <- rnorm(4);    
     ran <- mean + as.vector( var.root %*% ran );         
  }
    main <- function()
	{
	   N <- 1000000;
	   sum <- numeric(4);

	   print(date());
	   mu <- numeric(4);
	   var.root <- matrix(0, 4, 4);
	   diag(var.root) <- rep(1, 4);	

	   for(i in 1:N)
	   {		  		
	      ran <- rmulti.norm(mu, var.root);		  
		  sum <- sum + outer(ran, ran);	  

		  }



		  sum <- sum/N;
		  print(sum);
		  print(date());
}

